// Navigation: See /robots.txt for the Cognitive Navigation Map
import SmartToolParser from "./smartParser";
import ExecutionEngine from "./executionEngine";
import CommandHandler from "./commandHandler";
import RepetitionDetector from "./repetitionDetector";
import logger from "./logger";
import ConfigManager from "./configManager";
import TurnProcessor from "./turnProcessor";
import HistoryManager from "./historyManager";

class ChatManager {
  constructor(assistant, tools, systemInstruction, ui, instanceMode = false) {
    this.assistant = assistant;
    this.tools = tools;
    this.systemInstruction = systemInstruction;
    this.ui = ui;
    this.instanceMode = instanceMode;
    this.configManager = new ConfigManager();
    this.temperature = parseFloat(
      this.configManager.get("default_temperature", 0.7),
    );
    this.contextWindowLimit = parseInt(
      this.configManager.get("context_window_limit", 250000),
      10,
    );
    this.tpmLimit = parseInt(this.configManager.get("tpm_limit", 15000), 10);
    this.ui.bashEnabled = false;
    this.currentChannel = "#main";
    this.timestampsEnabled = this.configManager.get(
      "timestamps_enabled",
      false,
    );
    this.safemode = this.configManager.get("safemode", false);
    this.parser = new SmartToolParser();
    this.engine = new ExecutionEngine(
      assistant,
      tools,
      this.parser,
      ui,
      instanceMode,
      null,
      this.systemInstruction === "",
    );
    this.commandHandler = new CommandHandler(this, ui);
    this.repetitionDetector = new RepetitionDetector();
    this.turnProcessor = new TurnProcessor(
      assistant,
      tools,
      this.parser,
      this.engine,
      ui,
      this.repetitionDetector,
    );
    this.historyManager = new HistoryManager(assistant, ui, this.configManager);
    this.assistant.ui = ui; // Inyectamos la UI en el adaptador para los reintentos
    this.ui.agentNickname = this.configManager.get(
      "agent_nickname",
      "paser_mini",
    );
    logger.setAgentNickname(this.ui.agentNickname);
    this.ui.userNickname = this.configManager.get("user_nickname", "user");
    this.setRenderingMode(this.configManager.get("rendering_mode", "IRC"));
    this.stopRequested = false;
    this.logOpened = false;
  }

  saveConfig(key, value) {
    if (this.instanceMode) {
      this.configManager.config[key] = value;
      return;
    }
    this.configManager.save(key, value);
  }

  setRenderingMode(mode) {
    this.saveConfig("rendering_mode", mode);
    this.ui.setRenderingMode(mode);
    if (this.assistant) {
      if (this.assistant.setRenderingMode) {
        this.assistant.setRenderingMode(mode);
      } else if (this.assistant.state?.setRenderingMode) {
        this.assistant.state.setRenderingMode(mode);
      }
    }
  }

  async switchProvider(provider, model, temperature) {
    const oldAssistant = this.assistant;
    let newAssistant;

    if (provider === "NVIDIA") {
      const { NvidiaAdapter } =
        await import("../infrastructure/nvidia/adapter");
      newAssistant = new NvidiaAdapter(
        this.configManager,
        this.ui.userNickname,
        this.ui.agentNickname,
      );
    } else if (provider === "OPENROUTER") {
      const { OpenRouterAdapter } =
        await import("../infrastructure/openrouter/adapter");
      newAssistant = new OpenRouterAdapter(
        this.ui,
        this.ui.userNickname,
        this.ui.agentNickname,
      );
    } else {
      const { GeminiAdapter } =
        await import("../infrastructure/gemini/adapter");
      newAssistant = new GeminiAdapter(
        this.ui,
        this.ui.userNickname,
        this.ui.agentNickname,
      );
    }

    // Migrate history
    if (oldAssistant && oldAssistant.getHistory) {
      const history = oldAssistant.getHistory();
      if (history?.length > 0) {
        history.forEach((msg) => {
          const text = msg.text ?? msg.parts?.[0]?.text ?? "";
          newAssistant.injectMessage(msg.role, text);
        });
      }
    }

    this.assistant = newAssistant;
    this.assistant.startChat(model, this.systemInstruction, temperature);

    // Synchronize references
    if (this.turnProcessor) {
      this.turnProcessor.assistant = newAssistant;
    }
    if (this.engine) {
      this.engine.assistant = newAssistant;
    }

    logger.info(`Provider switched to ${provider} | Model: ${model}`);
  }

  async run(initialInput = null) {
    logger.info("Initializing ChatManager.run");

    const model = this.configManager.get("model_name", "gemini-2.0-flash");
    this.assistant.startChat(model, this.systemInstruction, this.temperature);

    this.ui.clearLog();

    if (initialInput) {
      const logMsg = this.ui.getLogOpenedString();
      const welcomeMsg = "-!- Session resumed from ./log/history.log";
      const combinedMsg = `${logMsg}\n${welcomeMsg}`;

      this.ui.displayChatMessage("system", combinedMsg);
      this.assistant.injectMessage("server", combinedMsg);

      this.logOpened = true;
      await this.processTurn(initialInput);
    }

    if (this.ui.initInput) {
      this.ui.initInput();
    }

    while (!this.stopRequested) {
      try {
        // eslint-disable-next-line no-await-in-loop
        const input = await this.ui.requestInput();
        if (input) {
          if (!this.logOpened && this.systemInstruction) {
            const logMsg = this.ui.getLogOpenedString();
            this.ui.displayChatMessage("system", logMsg);
            this.ui.displayChatMessage(
              "system",
              "*** Session resumed from ./log/history.log",
            );
            this.logOpened = true;
            const formattedLog =
              this.ui.renderingMode === "FOUNTAIN"
                ? this.ui._renderFountain("system", logMsg)
                : logMsg;
            this.assistant.injectMessage("server", formattedLog);
          }

          // eslint-disable-next-line no-await-in-loop
          const handled = await this.commandHandler.handle(input);
          if (!handled) {
            this.ui.displayChatMessage(this.ui.userNickname, input);
            // eslint-disable-next-line no-await-in-loop
            await this.processTurn(input);
          }
        }
      } catch (e) {
        if (e.name === "UserInterruptException") {
          logger.info("Turn interrupted by user input");
          this.ui.displayInfo("Agent interrupted. Processing new request...");
        } else if (e.name === "APIError") {
          this.ui.displayError(
            `Error de conexión con la IA: ${e.message}. La sesión sigue activa, intenta de nuevo en un momento.`,
          );
          console.error(e);
        } else {
          this.ui.displayError(`Critical error in processTurn: ${e.message}`);
          console.error(e);
        }
      }
    }
  }

  async processTurn(userInput) {
    return this.turnProcessor.process(userInput);
  }

  stopExecution() {
    this.stopRequested = true;
  }
}


export default ChatManager;

import SystemCommands from "./system";
import ModelCommands from "./models";
import ConfigCommands from "./config";
import FavoriteCommands from "./favorites";
import SessionCommands from "./session";
import InterfaceCommands from "./interface";
import AICommands from "./ai";

const COMMAND_MAP = {
  "/q": (cm) => SystemCommands.handleExit(cm),
  "/quit": (cm) => SystemCommands.handleExit(cm),
  "/exit": (cm) => SystemCommands.handleExit(cm),
  ":q": (cm) => SystemCommands.handleExit(cm),
  "/reset": SystemCommands.handleReset,
  "/clear": (_, ui) => SystemCommands.handleClear(ui),
  "/kick": SystemCommands.handleKick,
  "/enablebash": SystemCommands.handleEnableBash,
  "/compact": SessionCommands.handleCompact,
  "/fountain": InterfaceCommands.handleFountain,
  "/irc": InterfaceCommands.handleIRC,
  "/clean": InterfaceCommands.handleClean,
  "/help": (_, ui) => InterfaceCommands.handleHelp(ui),
  "/connect": AICommands.handleConnect,
  "/config": ConfigCommands.handleConfig,
  "/models_check": (cm, ui) => ModelCommands.handleModelsCheck(cm, ui),
};

const PREFIX_COMMANDS = {
  "/r ": (cm, ui, input) =>
    SessionCommands.handleRewrite(cm, ui, input.slice(3).trim()),
  "/s ": (cm, ui, input) =>
    SessionCommands.handleSavePayload(
      cm,
      ui,
      input.slice(3).trim() || "last_request.json",
    ),
  "/topic ": (cm, ui, input) =>
    InterfaceCommands.handleTopic(cm, ui, input.slice(7).trim()),
  "/nick ": (cm, ui, input) =>
    InterfaceCommands.handleNick(cm, ui, input.slice(6).trim()),
  "/me ": (cm, ui, input) =>
    InterfaceCommands.handleMe(cm, ui, input.slice(4).trim()),
  "/action ": (cm, ui, input) =>
    InterfaceCommands.handleAction(cm, ui, input.slice(8).trim()),
  "/join ": (cm, ui, input) =>
    InterfaceCommands.handleJoin(cm, ui, input.slice(6).trim()),
  "/paim ": (cm, ui, input) =>
    AICommands.handlePaim(cm, ui, input.slice(6).trim()),
  "/models": (cm, ui, input) =>
    ModelCommands.handleModels(cm, ui, input.split(/\s+/)),
  "/fav": (cm, ui, input) =>
    FavoriteCommands.handleFav(cm, ui, input.split(/\s+/)),
};

class CommandHandler {
  constructor(chatManager, ui) {
    this.chatManager = chatManager;
    this.ui = ui;
  }

  _handleWindowConfig(input) {
    const parts = input.split(/\s+/);
    if (parts.length !== 4) {
      this.ui.displayError("Usage: /w <tokens> <rpm_limit> <tpm_limit>");
      return true;
    }
    const [, tokens, rpm, tpm] = parts.map((p) => parseInt(p, 10));
    this.chatManager.configManager.save("context_window_limit", tokens);
    this.chatManager.configManager.save("rpm_limit", rpm);
    this.chatManager.configManager.save("tpm_limit", tpm);
    this.ui.displayInfo(
      `Context window: ${tokens} | RPM: ${rpm} | TPM: ${tpm}`,
    );
    return true;
  }

  async handle(userInput) {
    const input = userInput.trim();
    const lowerInput = input.toLowerCase();

    if (COMMAND_MAP[lowerInput])
      return COMMAND_MAP[lowerInput](this.chatManager, this.ui);

    const prefixKey = Object.keys(PREFIX_COMMANDS).find((key) =>
      lowerInput.startsWith(key),
    );
    if (prefixKey)
      return PREFIX_COMMANDS[prefixKey](this.chatManager, this.ui, input);

    if (input.startsWith("/w ")) return this._handleWindowConfig(input);

    if (input.startsWith("/") || input.startsWith(":")) {
      this.ui.displayError(
        "Invalid command. See /help for available commands.",
      );
      return true;
    }
    return false;
  }
}


export default CommandHandler;

class AICommands {
  static async handlePaim(chatManager, ui, message) {
    const content =
      ui.renderingMode === "FOUNTAIN"
        ? ui._renderFountain(ui.agentNickname, message)
        : message;
    chatManager.assistant.injectMessage("model", content);
    ui.displayChatMessage(ui.agentNickname, message);
    return true;
  }

  static async handleConnect(chatManager, ui) {
    ui.displayMessage("Select Provider:\n0: Gemini\n1: NVIDIA");
    const choice = await ui.requestInput("Provider: ");

    let provider;
    let model;
    if (choice === "0") {
      provider = "Gemini";
      model = "gemini-2.0-flash";
    } else if (choice === "1") {
      provider = "NVIDIA";
      model = "meta/llama-3.1-405b-instruct";
    } else {
      ui.displayError("Invalid provider.");
      return true;
    }

    await chatManager.switchProvider(provider, model, chatManager.temperature);
    chatManager.configManager.save("provider", provider);
    chatManager.configManager.save("model_name", model);
    ui.displayInfo(`Connected to ${provider}`);
    return true;
  }
}


export default AICommands;

class InterfaceCommands {
  static handleFountain(chatManager, ui) {
    chatManager.setRenderingMode("FOUNTAIN");
    ui.displayInfo("Rendering mode set to Fountain (Screenplay)");
    return true;
  }

  static handleIRC(chatManager, ui) {
    chatManager.setRenderingMode("IRC");
    ui.displayInfo("Rendering mode set to IRC (Default)");
    return true;
  }

  static handleClean(chatManager, ui) {
    chatManager.setRenderingMode("CLEAN");
    ui.displayInfo("Rendering mode set to Clean (Minimalist)");
    return true;
  }

  static async handleTopic(chatManager, ui, topic) {
    ui.displaySystemMessage(`Topic changed to: ${topic}`);
    const actionMsg = `SCENE: ${topic}`;
    await chatManager.processTurn(`* ${actionMsg} *`);
    return true;
  }

  static async handleNick(chatManager, ui, newNick) {
    const oldNick = ui.userNickname;
    chatManager.configManager.save("user_nickname", newNick);
    // eslint-disable-next-line no-param-reassign
    ui.userNickname = newNick;
    chatManager.assistant.updateNicknames(newNick, ui.agentNickname);
    ui.displaySystemMessage(`${oldNick} changes his alias to ${newNick}`);
    const actionMsg = `changes his alias to ${newNick}`;
    await chatManager.processTurn(`*** ${actionMsg}`);
    return true;
  }

  static async handleMe(chatManager, ui, action) {
    const formattedAction = `* ${action} *`;
    ui.displayChatMessage(ui.userNickname, formattedAction);
    await chatManager.processTurn(formattedAction);
    return true;
  }

  static async handleAction(chatManager, ui, actionText) {
    if (ui.renderingMode === "FOUNTAIN") {
      ui.displaySystemMessage(actionText);
      const formatted = ui._renderFountain(
        "system",
        `* ACTION: ${actionText} *`,
      );
      chatManager.assistant.injectMessage("server", formatted);
    } else {
      const formattedAction = `*** [Action]: ${actionText}`;
      ui.displaySystemMessage(formattedAction);
      chatManager.assistant.injectMessage("server", formattedAction);
    }
    return true;
  }

  static async handleInsertSceneFountain(chatManager, ui, scene, action) {
    const formattedScene = scene.toUpperCase();
    const formattedAction = action.startsWith("/") ? action : `/${action}`;
    const output = `\n${formattedScene}\n${formattedAction}\n`;
    ui.displaySystemMessage(`Injecting: ${output}`);
    chatManager.assistant.injectMessage("user", output);
    return "OK";
  }

  static async handleJoin(chatManager, ui, channel) {
    if (ui.renderingMode !== "FOUNTAIN" && !channel.startsWith("#")) {
      ui.displayError("Channel name must start with # (e.g., /join #work)");
      return true;
    }
    // eslint-disable-next-line no-param-reassign
    chatManager.currentChannel = channel;
    if (ui.renderingMode === "FOUNTAIN") {
      ui.displaySystemMessage(`Scene changed to: ${channel}`);
      await chatManager.processTurn(`* SCENE: ${channel} *`);
    } else {
      let modeDesc = "General purpose mode.";
      if (channel === "#charla") {
        modeDesc = "Casual, friendly, and conversational mode.";
      } else if (channel === "#work") {
        modeDesc =
          "Professional, focused, and highly efficient engineering mode.";
      }
      const systemMsg = `Joined channel ${channel}. Mode: ${modeDesc}`;
      ui.displaySystemMessage(systemMsg);
      const content =
        ui.renderingMode === "FOUNTAIN"
          ? ui._renderFountain("system", systemMsg)
          : systemMsg;
      chatManager.assistant.injectMessage("server", content);
    }
    return true;
  }

  static handleHelp(ui) {
    const helpText =
      "\nAvailable Commands:\n-------------------\n" +
      "/help       - Show this help menu\n" +
      "/config     - Show current system configuration\n" +
      "/models     - Change AI model and temperature\n" +
      "/fav        - Manage favorite models (/fav, /fav+, /fav -<idx>, /fav <idx>)\n" +
      "/reset      - Hard Reset: Clear history and Leap via Bridge Block\n" +
      "/r <msg>    - Rewrite: Remove last interaction and re-prompt\n" +
      "/w <t> <r> <p> - Set window, RPM, and TPM\n" +
      "/clear      - Clear terminal\n" +
      "/fountain   - Set rendering mode to Screenplay\n" +
      "/irc        - Set rendering mode to IRC (default)\n" +
      "/clean      - Set rendering mode to Clean (Minimalist)\n" +
      "/topic <text> - Change the channel topic\n" +
      "/nick <name> - Change the agent's nickname\n" +
      "/me <action> - Perform an action (roleplay)\n" +
      "/compact    - Compact history into IRC log and reset context\n" +
      "/action <txt> - Perform a narrative action (full-width)\n" +
      "/kick       - Kick agent: Nuclear reset, wipes all session memory\n" +
      "/paim <msg>  - Simulate AI response (Pishin AI Message)\n" +
      "/join <#ch> - Change channel and mode (#charla, #work)\n" +
      "/s [file]   - Save last request payload to JSON\n" +
      "/q, /quit, /exit - Exit application\n";
    ui.displayMessage(helpText);
    return true;
  }
}


export default InterfaceCommands;

import MementoManager from "./manager";

class SystemCommands {
  static handleClear() {
    process.stdout.write("\x1Bc");
    return true;
  }

  static handleExit(chatManager) {
    // eslint-disable-next-line no-param-reassign
    chatManager.shouldExit = true;
    process.exit(0);
  }

  static async handleReset(chatManager, ui) {
    ui.displayInfo("Performing Hard Reset (The Leap)...");
    const manager = new MementoManager();
    const bridge = await manager.pullMemory("bridge", null, "next");
    const newHistory = [];
    if (bridge) {
      const bridgeMsg = `[MEMENTO LEAP: RESTORED SESSION STATE]\nNode #${bridge.id} | ${bridge.content}`;
      newHistory.push({ role: "user", parts: [{ text: bridgeMsg }] });
      ui.displayInfo(`Bridge Block #${bridge.id} restored.`);
    } else {
      ui.displayInfo("No Bridge Block found. Starting fresh.");
    }
    chatManager.assistant.hardReset(newHistory);
    return true;
  }

  static async handleKick(chatManager, ui) {
    ui.displaySystemMessage("*** Agent kicked. Session wiped. Restarting...");
    chatManager.assistant.hardReset();
    ui.clearLog();
    ui.displayLogOpened();
    return true;
  }

  static handleEnableBash(chatManager, ui) {
    // eslint-disable-next-line no-param-reassign
    ui.bashEnabled = true;
    ui.displayInfo("Bash access enabled. You can now use executeBash.");
    const bashInstruction =
      "SYSTEM UPDATE: Bash access has been enabled. You now have access to the tool `executeBash(command: string)`, which allows you to execute shell commands in the project root.";
    const content =
      ui.renderingMode === "FOUNTAIN"
        ? ui._renderFountain("system", bashInstruction)
        : bashInstruction;
    chatManager.assistant.injectMessage("server", content);
    return true;
  }
}


export default SystemCommands;

import fs from "fs";
import path from "path";
import { fileURLToPath } from "url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));

class ConfigManager {
  constructor() {
    this.configPath = path.join(__dirname, "..", "..", "config", "config.json");
    this.config = this._loadConfig();
  }

  _loadConfig() {
    try {
      return fs.existsSync(this.configPath)
        ? JSON.parse(fs.readFileSync(this.configPath, "utf8"))
        : {};
    } catch {
      return {};
    }
  }

  get(key, defaultValue = null) {
    return this.config[key] ?? defaultValue;
  }

  save(key, value) {
    this.config[key] = value;
    const dir = path.dirname(this.configPath);
    if (!fs.existsSync(dir)) {
      fs.mkdirSync(dir, { recursive: true });
    }
    fs.writeFileSync(
      this.configPath,
      JSON.stringify(this.config, null, 4),
      "utf8",
    );
  }
}


export default ConfigManager;

// Navigation: See /robots.txt for the Cognitive Navigation Map
import path from "path";
import ToolAttemptTracker from "./toolTracker";
import { TOOL_ALIASES } from "../tools/registry";

class ExecutionEngine {
  constructor(
    assistant,
    tools,
    toolParser,
    ui,
    instanceMode = false,
    tracker = null,
    pureMode = false,
  ) {
    this.assistant = assistant;
    this.tools = tools;
    this.toolParser = toolParser;
    this.ui = ui;
    this.instanceMode = instanceMode;
    this.toolTracker = tracker || new ToolAttemptTracker();
    this.strictPureMode = pureMode || false;
    this.turnCount = 0;
    this.maxTurns = 10000;
    this.stopRequested = false;
    this._detailMappers = {
      readFile: (a) => path.basename(a.path || ""),
      writeFile: (a) => path.basename(a.path || ""),
      removeFile: (a) => path.basename(a.path || ""),
      replaceString: (a) => path.basename(a.path || ""),
      listDir: (a) => a.path || "",
      createDir: (a) => a.path || "",
      renamePath: (a) =>
        `${path.basename(a.origin || "")} -> ${path.basename(a.destination || "")}`,
      pushMemory: (a) => a.key || "unknown",
      pullMemory: (a) => a.key || "unknown",
      runInstance: (a) => a.target || "unknown",
      searchTextGlobal: (a) => `${a.query || ""}`,
      searchFilesPattern: (a) => `pattern: ${a.pattern || ""}`,
      analyzeCode: (a) => path.basename(a.path || ""),
      lintCode: (a) => path.basename(a.path || ""),
      generateDocs: (a) =>
        `Docs for ${path.basename(a.path || ".")} -> ${a.outputDir || "docs/api"}`,
      executeBash: (a) =>
        a.command.substring(0, 50) + (a.command.length > 50 ? "..." : ""),
      runPython: (a) => path.basename(a.scriptPath || ""),
      binaryAnalysis: (a) =>
        `${a.action || "analysis"} on ${path.basename(a.filePath || "unknown")}`,
      sh: (a) =>
        `sh: ${a.command.substring(0, 50)}${a.command.length > 50 ? "..." : ""}`,
    };
  }

  async executeToolCall(name, args, callData) {
    const displayName = name;
    const toolName = TOOL_ALIASES[name] || name;

    if (this.strictPureMode) {
      return {
        response: this.toolParser.formatToolResponse(
          "ERR: Pure Mode active. Tool execution is strictly disabled.",
          callData.id,
          false,
        ),
        success: false,
      };
    }
    if (!this.toolTracker.recordAttempt(toolName, args)) {
      return {
        response: this.toolParser.formatToolResponse(
          `Tool loop detected: ${toolName} called too many times.`,
          callData.id,
          false,
        ),
        success: false,
      };
    }

    if (toolName === "executeBash" && !this.ui.bashEnabled) {
      return {
        response: this.toolParser.formatToolResponse(
          "ERR: Bash access is disabled for security. Please use /enableBash to activate it.",
          callData.id,
          false,
        ),
        success: false,
      };
    }

    if (!(toolName in this.tools)) {
      return {
        response: this.toolParser.formatToolResponse(
          `Unknown tool: ${toolName}`,
          callData.id,
          false,
        ),
        success: false,
      };
    }

    if (toolName === "runInstance" && this.instanceMode === true) {
      return {
        response: this.toolParser.formatToolResponse(
          "ERR: Recursion disabled.",
          callData.id,
          false,
        ),
        success: false,
      };
    }

    if (toolName === "sh") {
      const result = await this.tools[toolName](args);
      return {
        response: this.toolParser.formatToolResponse(result, callData.id, true),
        result,
        success: true,
      };
    }

    // Safe detail mapping
    let detail = "no details";
    try {
      const mapper = this._detailMappers[toolName] ?? (() => "no details");
      detail = mapper(args);
    } catch (e) {
      detail = "error mapping details";
    }

    this.ui.startToolMonitoring(displayName, detail);

    try {
      const toolFunc = this.tools[toolName];
      const result = await toolFunc(args);

      if (toolName === "pullMemory") {
        this.ui.displayPanel(
          "Memento Pull",
          `Accessing node #${args.key}`,
          "info",
        );
      } else if (toolName === "pushMemory") {
        this.ui.displayPanel("Memento Push", result, "info");
      } else if (toolName === "runInstance") {
        this.ui.displayPanel("Instance Test Output", result, "info");
      }

      this.toolTracker.recordSuccess(toolName);
      this.ui.endToolMonitoring(displayName, true, detail);

      return {
        response: this.toolParser.formatToolResponse(result, callData.id, true),
        result,
        success: true,
      };
    } catch (e) {
      this.toolTracker.recordFailure(toolName);
      this.ui.endToolMonitoring(displayName, false, detail);
      return {
        response: this.toolParser.formatToolResponse(
          `ERR: ${e.message}`,
          callData.id,
          false,
        ),
        success: false,
      };
    }
  }
}


export default ExecutionEngine;

import * as githubTools from "../tools/githubTools";
import GitHubUI from "./githubUI";
import ChatManager from "./chatManager";
import { GeminiAdapter } from "../infrastructure/gemini/adapter";

class GitHubModeOrchestrator {
  constructor(systemInstruction, tools) {
    this.systemInstruction = systemInstruction;
    this.tools = tools;
    this.processingLabel = "paser-processing";
    this.triggerHashtag = "#ai-assistance";
    this.botLogin = null;
  }

  async run() {
    if (!this.botLogin) {
      const userData = await githubTools.get_authenticated_user();
      this.botLogin = userData.login;
    }
    const issues = await githubTools.listIssues();
    const filtered = issues.filter(
      (i) =>
        (i.body || "").includes(this.triggerHashtag) &&
        !(i.labels || []).map((l) => l.name).includes(this.processingLabel),
    );

    for (let i = 0; i < filtered.length; i += 1) {
      // eslint-disable-next-line no-await-in-loop
      await this.processIssue(filtered[i]);
    }
  }

  async processIssue(issue) {
    const { number: issueNumber, body: issueBody = "" } = issue;
    await githubTools.add_label({
      issue_number: issueNumber,
      label: this.processingLabel,
    });
    try {
      const ui = new GitHubUI(issueNumber);
      const chatManager = new ChatManager(
        new GeminiAdapter(),
        this.tools,
        this.systemInstruction,
        ui,
        true,
      );
      await chatManager.run(
        `SYSTEM: GitHub Issue #${issueNumber}.\n${issueBody}`,
      );
    } finally {
      await githubTools.remove_label({
        issue_number: issueNumber,
        label: this.processingLabel,
      });
    }
  }
}


export default GitHubModeOrchestrator;

import * as githubTools from "../tools/githubTools";

class GitHubUI {
  constructor(issueNumber, repo = null) {
    this.issueNumber = issueNumber;
    this.repo = repo;
  }

  // eslint-disable-next-line no-unused-vars
  async requestInput(_prompt) {
    // In GitHub mode, input is managed by the orchestrator via message queue
    return "";
  }

  displayMessage(text) {
    console.log(`[POSTING TO GITHUB] Issue #${this.issueNumber}: ${text}`);
    try {
      // Nota: githubTools.postComment es async
      githubTools
        .postComment({
          issue_number: this.issueNumber,
          body: text,
          repo: this.repo,
        })
        .catch((e) => console.error(`Failed to post comment: ${e.message}`));
    } catch (e) {
      console.error(`Error in displayMessage: ${e.message}`);
    }
  }

  displayThought(text) {
    console.log(`[THOUGHT] [Issue ${this.issueNumber}] ${text}`);
  }

  displayInfo(message) {
    console.log(`[INFO] [Issue ${this.issueNumber}] ${message}`);
  }

  displayError(message) {
    console.error(`[ERROR] [Issue ${this.issueNumber}] ${message}`);
  }

  displayToolStatus(toolName, success, detail = "") {
    const status = success ? "OK" : "FAIL";
    console.log(
      `[TOOL] [Issue ${this.issueNumber}] ${toolName} -> ${status} ${detail}`,
    );
  }

  async getConfirmation(message) {
    console.log(
      `[CONFIRMATION REQUEST] [Issue ${this.issueNumber}] ${message} -> Defaulting to True`,
    );
    return true;
  }

  // eslint-disable-next-line no-unused-vars
  startToolMonitoring(_toolName, _detail = "") {
    // eslint-disable-next-line no-unused-expressions
    this.issueNumber;
  }

  // eslint-disable-next-line no-unused-vars
  endToolMonitoring(_toolName, _success) {
    // eslint-disable-next-line no-unused-expressions
    this.issueNumber;
  }

  stopAllMonitoring() {
    // eslint-disable-next-line no-unused-expressions
    this.issueNumber;
  }

  addSpacing() {
    // eslint-disable-next-line no-unused-expressions
    this.issueNumber;
  }

  updateQueueCount() {
    // eslint-disable-next-line no-unused-expressions
    this.issueNumber;
  }
}

export default GitHubUI;

import fs from "fs";
import path from "path";

class Logger {
  constructor() {
    this.logFile = path.join(process.cwd(), "log", "paser_mini.log");
    this.sessionFile = path.join(process.cwd(), "log", "session.log");
    this.historyFile = path.join(process.cwd(), "log", "history.log");
    this.agentNickname = null;

    // Asegurar que el directorio log existe
    if (!fs.existsSync(path.join(process.cwd(), "log"))) {
      fs.mkdirSync(path.join(process.cwd(), "log"));
    }

    // Clear the logs when starting the application
    fs.writeFileSync(
      this.logFile,
      `--- Session Started: ${new Date().toISOString()} ---\n`,
    );
    fs.writeFileSync(
      this.sessionFile,
      `--- Session Started: ${new Date().toISOString()} ---\n`,
    );
    fs.writeFileSync(
      this.historyFile,
      `--- Session Started: ${new Date().toISOString()} ---\n`,
    );
  }

  _log(level, message, data = null) {
    const timestamp = new Date().toISOString();
    let targetFile = this.logFile;
    if (level === "THOUGHT") {
      targetFile = this.sessionFile;
    } else if (level === "HISTORY") {
      targetFile = this.historyFile;
    }

    if (level === "THOUGHT") {
      const time = new Date().toLocaleTimeString("en-GB", {
        hour: "2-digit",
        minute: "2-digit",
        second: "2-digit",
        hour12: false,
      });
      const nick = this.agentNickname || "agent";
      const logEntry = `[${time}] <${nick}> * thought: ${message}\n`;
      fs.appendFileSync(targetFile, logEntry, "utf8");
      return;
    }

    const logEntry = `[${timestamp}] [${level}] ${message} ${data ? JSON.stringify(data) : ""}\n`;
    fs.appendFileSync(targetFile, logEntry, "utf8");
  }

  setAgentNickname(nick) {
    this.agentNickname = nick;
  }

  info(msg, data) {
    this._log("INFO", msg, data);
  }

  warn(msg, data) {
    this._log("WARN", msg, data);
  }

  error(msg, data) {
    this._log("ERROR", msg, data);
  }

  sessionLog(msg) {
    this._log("THOUGHT", msg);
  }

  historyLog(msg) {
    this._log("HISTORY", msg);
  }

  debug(msg, data) {
    this._log("DEBUG", msg, data);
  }
}

const logger = new Logger();


export default logger;

class BaseRenderer {
  constructor(ui) {
    this.ui = ui;
  }

  /**
   * @param {Object} message - The raw message object
   * @param {string} message.nickname - The sender's nickname
   * @param {string} message.text - The raw text content
   * @param {string} [message.time] - Formatted timestamp
   * @param {string} [message.type] - 'chat', 'system', 'error', 'info', 'thought'
   * @returns {string} The formatted string for terminal output
   */
  render(_message) {
    throw new Error("render() must be implemented by subclass");
  }
}


export default BaseRenderer;

import BaseRenderer from "./renderer_base";

class FountainRenderer extends BaseRenderer {
  _wrapText(text, start, end) {
    const width = end - start;
    const words = text.split(/\s+/);
    const lines = [];
    let currentLine = "";

    words.forEach((word) => {
      if ((currentLine + (currentLine ? " " : "") + word).length <= width) {
        currentLine += (currentLine ? " " : "") + word;
      } else {
        lines.push(currentLine);
        currentLine = word;
      }
    });
    lines.push(currentLine);

    return lines.map((line) => `${" ".repeat(start)}${line}`).join("\n");
  }

  render(message) {
    const { nickname, text, type } = message;
    const trimmedText = text.trim();

    // Filter out tool calls and tool responses from visual output
    if (
      trimmedText.includes("<TOOL_CALL>") ||
      trimmedText.includes("<TOOL_RESPONSE>")
    ) {
      return "";
    }

    let output = "";

    if (type === "system") {
      if (trimmedText.startsWith("* SCENE:")) {
        const sceneText = trimmedText
          .replace(/^\* SCENE:\s*|\s*\*$/g, "")
          .toUpperCase();
        output = `\n${sceneText}\n`;
      } else {
        const cleanText = trimmedText.replace(
          /^(\* ACTION:\s*|\*\*\*|---|-!-)\s*|\s*\*$/g,
          "",
        );
        output = this._wrapText(cleanText, 0, 75);
      }
    } else if (nickname === "dialogue") {
      if (trimmedText.startsWith("*")) {
        const cleanText = trimmedText.replace(/^\*\s*|\s*\*$/g, "");
        output += this._wrapText(`(${cleanText})`, 31, 60);
      } else {
        output += this._wrapText(trimmedText, 25, 60);
      }
    } else {
      output += `${" ".repeat(37)}${nickname.toUpperCase()}\n`;

      if (trimmedText.startsWith("*")) {
        const cleanText = trimmedText.replace(/^\*\s*|\s*\*$/g, "");
        output += this._wrapText(`(${cleanText})`, 31, 60);
      } else {
        output += this._wrapText(this.ui.formatMarkdown(trimmedText), 25, 60);
      }
    }

    return `${output}\n`;
  }
}


export default FountainRenderer;

import fs from "fs";
import path from "path";
import { fileURLToPath } from "url";
import SchemaValidator from "./schemaValidator";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const SCHEMAS_DIR = path.join(__dirname, "schemas");

const validator = new SchemaValidator();

async function registerSchemas() {
  try {
    const files = fs.readdirSync(SCHEMAS_DIR);

    for (let i = 0; i < files.length; i += 1) {
      const file = files[i];
      if (file.endsWith(".js")) {
        const schemaName = file.replace(".js", "").replace("Schema", "");
        const toolName = schemaName;

        try {
          // eslint-disable-next-line no-await-in-loop
          const module = await import(`./schemas/${file}?update=${Date.now()}`);
          const schema = module[`${schemaName}Schema`];

          if (schema) {
            validator.registerSchema(toolName, schema);
          } else {
            console.error(
              `[SchemaRegistry] Warning: No export named ${schemaName}Schema found in ${file}`,
            );
          }
        } catch (e) {
          console.error(
            `[SchemaRegistry] Error loading schema ${file}: ${e.message}`,
          );
        }
      }
    }
  } catch (e) {
    console.error(
      `[SchemaRegistry] Critical error reading schemas directory: ${e.message}`,
    );
  }
}

// Top-level await ensures all schemas are registered before the validator is exported
await registerSchemas();

export { registerSchemas };
export default validator;

import AutoCorrector from "./autoCorrector";
import validator from "./schemaRegistry";

import { TOOL_ALIASES } from "../tools/registry";

class SmartToolParser {
  // Optimized regex: limits capture to 10k characters to avoid blocking the main thread
  static TOOL_PATTERN =
    /<(?:TOOL_CALL|tool_call)\s*>([\s\S]{1,10000}?)(?:<\/(?:TOOL_CALL|tool_call)>|$)/gis;

  constructor() {
    this.validator = validator;
    this.corrector = AutoCorrector;
  }

  parseCall(rawContent) {
    let data;
    try {
      data = JSON.parse(rawContent);
    } catch (e) {
      try {
        data = JSON.parse(this.corrector.fixJson(rawContent));
      } catch (e2) {
        return { data: null, error: "Invalid JSON format." };
      }
    }

    if (!data || typeof data !== "object" || !data.name) {
      return { data: null, error: "Missing 'name' field." };
    }

    if (typeof data.name === "string" && data.name.endsWith("()")) {
      data.name = data.name.slice(0, -2);
    }

    // Resolve alias to canonical name for validation
    if (typeof data.name === "string" && TOOL_ALIASES[data.name]) {
      data.name = TOOL_ALIASES[data.name];
    }

    data.args = data.args || {};

    const validation = this.validator.validate(data.name, data.args);
    if (!validation.isValid) {
      return {
        data: null,
        error: `Validation error: ${validation.errors.join("; ")}`,
      };
    }

    return { data, error: null };
  }

  extractToolCalls(text) {
    const results = [];
    let match;
    SmartToolParser.TOOL_PATTERN.lastIndex = 0;

    while ((match = SmartToolParser.TOOL_PATTERN.exec(text)) !== null) {
      const content = match[1].trim();
      const { data, error } = this.parseCall(content);
      results.push({ data, content, error });
    }

    return results;
  }

  formatToolResponse(data, callId = null, success = true) {
    return `<TOOL_RESPONSE>${JSON.stringify({
      id: callId,
      status: success ? "success" : "error",
      data,
    })}</TOOL_RESPONSE>`;
  }

  cleanResponse(text) {
    if (!text) return "";
    return text.replace(/<[^>]+>.*?<\/[^>]+>/gs, "");
  }
}


export default SmartToolParser;

import chalk from "chalk";
import ora from "ora";
import fs from "fs";
import readline from "readline";

class TerminalUI {
  // eslint-disable-next-line no-unused-vars
  constructor(options = {}) {
    this.noSpinner = true; // Forced to true to prevent TTY crashes during tool execution
    this.activeSpinners = new Map();

    this.agentNickname = "paser_mini";
    this.userNickname = "user";
    this.renderingMode = "IRC"; // 'IRC' or 'FOUNTAIN'
    this.inputQueue = [];
    this.rl = null;
    this.inputResolver = null;
  }

  setRenderingMode(mode) {
    this.renderingMode = mode;
  }

  _wrapText(text, start, end) {
    const width = end - start;
    const words = text.split(/\s+/);
    const lines = [];
    let currentLine = "";

    words.forEach((word) => {
      if ((currentLine + (currentLine ? " " : "") + word).length <= width) {
        currentLine += (currentLine ? " " : "") + word;
      } else {
        lines.push(currentLine);
        currentLine = word;
      }
    });
    lines.push(currentLine);

    return lines.map((line) => " ".repeat(start) + line).join("\n");
  }

  _renderFountain(nickname, text) {
    const trimmedText = text.trim();
    let output = "";

    if (nickname === "system") {
      // Scene Heading or Action
      if (trimmedText.startsWith("* SCENE:")) {
        const sceneText = trimmedText
          .replace(/^\* SCENE:\s*|\s*\*$/g, "")
          .toUpperCase();
        output = `\n${sceneText}\n`;
      } else {
        const cleanText = trimmedText.replace(
          /^(\* ACTION:\s*|\*\*\*|---|-!-)\s*|\s*\*$/g,
          "",
        );
        output = this._wrapText(cleanText, 0, 75);
      }
    } else if (nickname === "dialogue") {
      // Dialogue without nickname
      if (trimmedText.startsWith("*")) {
        const cleanText = trimmedText.replace(/^\*\s*|\s*\*$/g, "");
        output += this._wrapText(`(${cleanText})`, 31, 60);
      } else {
        output += this._wrapText(trimmedText, 25, 60);
      }
    } else {
      // Character and Dialogue/Parenthetical
      output += `${" ".repeat(37) + nickname.toUpperCase()}\n`;

      if (trimmedText.startsWith("*")) {
        // Parenthetical
        const cleanText = trimmedText.replace(/^\*\s*|\s*\*$/g, "");
        output += this._wrapText(`(${cleanText})`, 31, 60);
      } else {
        // Dialogue
        output += this._wrapText(trimmedText, 25, 60);
      }
    }
    return output;
  }

  writeToLog(text) {
    try {
      fs.appendFileSync("session.log", `${text}\n`, "utf8");

      // Immediate persistence for system events (-!-)
      if (text.includes("-!-")) {
        fs.appendFileSync("session_history.log", `${text}\n`, "utf8");
      }
    } catch (e) {
      console.error(`[Log Error] ${e.message}`);
    }
  }

  clearLog() {
    try {
      if (fs.existsSync("session.log")) {
        const content = fs.readFileSync("session.log", "utf8");
        if (content) {
          fs.appendFileSync("session_history.log", `${content}\n`, "utf8");
        }
      }
      fs.writeFileSync("session.log", "", "utf8");
    } catch (e) {
      console.error(`[Log Error] ${e.message}`);
    }
  }

  /**
   * Renderiza una tabla de Markdown en formato de terminal
   */
  renderTable(tableText) {
    const lines = tableText.trim().split("\n");
    if (lines.length < 2) return tableText;

    const rows = lines
      .filter((line) => line.includes("|"))
      .map((line) =>
        line
          .split("|")
          .filter((cell, index, array) => {
            if (index === 0 && cell.trim() === "") return false;
            if (index === array.length - 1 && cell.trim() === "") return false;
            return true;
          })
          .map((cell) => cell.trim()),
      );

    const dataRows = rows.filter(
      (row) => !row.every((cell) => /^[:\s-]*$/.test(cell)),
    );

    if (dataRows.length === 0) return tableText;

    const colWidths = [];
    dataRows.forEach((row) => {
      row.forEach((cell, i) => {
        colWidths[i] = Math.max(colWidths[i] || 0, cell.length);
      });
    });

    let output = "";
    const separator = `+${colWidths.map((w) => "-".repeat(w + 2)).join("+")}+`;

    output += `${separator}\n`;
    dataRows.forEach((row, rowIndex) => {
      const line = `| ${row
        .map((cell, i) => cell.padEnd(colWidths[i]))
        .join(" | ")} |`;
      output += `${chalk.white(line)}\n`;
      if (rowIndex === 0) output += `${separator}\n`;
    });
    output += separator;

    return `\n${output}\n`;
  }

  /**
   * Formatea texto Markdown básico usando chalk para la terminal
   */
  formatMarkdown(text) {
    if (!text) return "";

    let formatted = text;

    const tableRegex = /((?:^\s*\|.*\n?)+)/gm;
    formatted = formatted.replace(tableRegex, (match) =>
      this.renderTable(match),
    );

    formatted = formatted.replace(
      /```([\s\S]*?)```/g,
      (_, code) => `\n${chalk.gray(code.trim())}\n`,
    );

    formatted = formatted.replace(/`([^`]+)`/g, (_, code) =>
      chalk.cyan(` ${code} `),
    );

    formatted = formatted.replace(/\*\*(.*?)\*\*/g, (_, content) =>
      chalk.bold(content),
    );

    formatted = formatted.replace(/\*(.*?)\*/g, (_, content) =>
      chalk.italic(content),
    );

    return formatted;
  }

  formatChatMessage(nickname, text, time = null) {
    const t =
      time ||
      new Date().toLocaleTimeString("en-GB", {
        hour: "2-digit",
        minute: "2-digit",
      });
    return `[${t}] <${nickname}> ${text}`;
  }

  displayChatMessage(nickname, text) {
    this._clearCurrentLine();
    const trimmedText = text.trim();

    if (this.renderingMode === "FOUNTAIN") {
      const fountainText = this._renderFountain(nickname, trimmedText);
      const renderedText = this.formatMarkdown(fountainText);
      process.stdout.write(`${renderedText}\n`);

      // Log the actual rendered layout to preserve the screenplay structure
      this.writeToLog(renderedText);
      this._restorePrompt();
      return;
    }

    if (this.renderingMode === "CLEAN") {
      const renderedText = this.formatMarkdown(trimmedText);
      process.stdout.write(`${renderedText}\n`);

      const now = new Date();
      const time = now.toLocaleTimeString("en-GB", {
        hour: "2-digit",
        minute: "2-digit",
      });
      this.writeToLog(`[${time}] <${nickname}> ${trimmedText}`);

      this._restorePrompt();
      return;
    }

    const renderedText = this.formatMarkdown(trimmedText);
    const now = new Date();
    const time = now.toLocaleTimeString("en-GB", {
      hour: "2-digit",
      minute: "2-digit",
    });

    if (
      trimmedText.startsWith("---") ||
      trimmedText.startsWith("***") ||
      trimmedText.startsWith("-!-")
    ) {
      const formatted = `[${time}] ${trimmedText}`;
      process.stdout.write(`${chalk.white(`[${time}]`)} ${renderedText}\n`);
      this.writeToLog(formatted);
    } else {
      const nameColor =
        nickname === this.agentNickname ? chalk.cyan : chalk.green;
      const formatted = `[${time}] <${nickname}> ${trimmedText}`;
      const prefix = `[${time}] <${nameColor(nickname)}>`;
      process.stdout.write(`${prefix} ${renderedText}\n`);
      this.writeToLog(formatted);
    }
    this._restorePrompt();
  }

  _clearCurrentLine() {
    if (this.rl) {
      process.stdout.write("\r\x1b[K");
    }
  }

  _restorePrompt() {
    // Removed rl.prompt to prevent redundant calls and potential terminal crashes
  }

  getLogOpenedString() {
    const now = new Date();
    const datePart = now.toDateString();
    const timePart = now.toTimeString().split(" ")[0];
    const [dayName, month, day, year] = datePart.split(" ");
    return `--- Log opened ${dayName} ${month} ${day} ${timePart} ${year} * Session resumed from ./log/history.log`;
  }

  displayLogOpened() {
    const logMsg = this.getLogOpenedString();
    this.displayChatMessage("user", logMsg);
  }

  displayMessage(text) {
    const renderedText = this.formatMarkdown(text);
    process.stdout.write(`${renderedText}\n`);
  }

  displayThought(text) {
    this._clearCurrentLine();
    process.stdout.write(`${chalk.green.italic(`\ud83d\udcad ${text}`)}\n`);
    this._restorePrompt();
  }

  // eslint-disable-next-line class-methods-use-this
  displayInfo(text) {
    this._clearCurrentLine();
    const now = new Date();
    const time = now.toLocaleTimeString("en-GB", {
      hour: "2-digit",
      minute: "2-digit",
    });
    process.stdout.write(`${chalk.blue("\u2139 ") + chalk.cyan(text)}\n`);
    this.writeToLog(`[${time}] [INFO] ${text}`);
    this._restorePrompt();
  }

  // eslint-disable-next-line class-methods-use-this
  displayError(text) {
    this._clearCurrentLine();
    const now = new Date();
    const time = now.toLocaleTimeString("en-GB", {
      hour: "2-digit",
      minute: "2-digit",
    });
    process.stdout.write(`${chalk.red("\u2716 ") + chalk.red.bold(text)}\n`);
    this.writeToLog(`[${time}] [ERROR] ${text}`);
    this._restorePrompt();
  }

  displaySystemMessage(text) {
    this.displayChatMessage("system", `*** ${text}`);
  }

  displayPanel(title, message, style = "none") {
    const border = "\u2500".repeat(title.length + 4);
    const panelColor = style === "warning" ? chalk.yellow : chalk.blue;

    process.stdout.write(`\n${panelColor(`\u250c${border}\u2510`)}\n`);
    process.stdout.write(
      `${panelColor("\u2502")} ${chalk.bold(title)} ${panelColor(
        " ".repeat(border.length - title.length - 2),
      )} ${panelColor("\u2502")}\n`,
    );
    process.stdout.write(
      `${panelColor(`\u251c${"\u2500".repeat(border.length)}\u2524`)}\n`,
    );
    process.stdout.write(
      `${panelColor("\u2502")} ${message} ${panelColor(
        " ".repeat(Math.max(0, border.length - message.length - 2)),
      )} ${panelColor("\u2502")}\n`,
    );
    process.stdout.write(`${panelColor(`\u2514${border}\u2518`)}\n\n`);
  }

  // eslint-disable-next-line no-unused-vars
  startToolMonitoring(_name, _detail) {
    const toolIcon = "\ud83d\udee0\ufe0f"; // \ud83d\udee0\ufe0f
    const msg = `${toolIcon} ${_name} (${_detail})...`;

    if (this.noSpinner) {
      process.stdout.write(`${chalk.yellow(msg)}\n`);
      return;
    }

    const spinner = ora({
      text: chalk.yellow(msg),
      color: "yellow",
    }).start();

    this.activeSpinners.set(_name, spinner);
  }

  updateMonitoring(name, text) {
    const spinner = this.activeSpinners.get(name);
    if (spinner) {
      spinner.text = text;
    }
  }

  displayToolStatus(name, success, detail) {
    const now = new Date();
    const time = now.toLocaleTimeString("en-GB", {
      hour: "2-digit",
      minute: "2-digit",
    });
    const nameColor = chalk.cyan;
    const statusIcon = success ? "✓" : "✗";
    const statusColor = success ? chalk.green : chalk.red;
    const prefix = `[${time}] <${nameColor(this.agentNickname)}>`;
    const finalMsg = `${prefix} * ${name} (${detail}) ${statusColor(statusIcon)}`;

    console.log(finalMsg);
    const plainStatus = success ? "✓" : "✗";
    const plainPrefix = `[${time}] <${this.agentNickname}>`;
    if (this.renderingMode === "FOUNTAIN") {
      const cleanToolLog = `${name} (${detail}) ${plainStatus}`;
      this.writeToLog(
        this._renderFountain("system", `* ACTION: ${cleanToolLog}`),
      );
    } else {
      this.writeToLog(`${plainPrefix} * ${name} (${detail}) ${plainStatus}`);
    }
  }

  endToolMonitoring(name, success, detail) {
    const spinner = this.activeSpinners.get(name);
    if (spinner) {
      spinner.stop();
    }

    this.displayToolStatus(name, success, detail);

    if (spinner) {
      this.activeSpinners.delete(name);
    }
  }

  stopAllMonitoring() {
    this.activeSpinners.forEach((spinner) => spinner.stop());
    this.activeSpinners.clear();
  }

  clear() {
    process.stdout.write("\x1Bc");
  }

  initInput() {
    if (this.rl) return;
    this.rl = readline.createInterface({
      input: process.stdin,
      output: process.stdout,
      terminal: true,
    });

    this.rl.on("line", (line) => {
      const trimmed = line.trim();
      if (trimmed) {
        if (this.inputResolver) {
          const resolve = this.inputResolver;
          this.inputResolver = null;
          resolve(trimmed);
        } else {
          this.inputQueue.push(trimmed);
        }
      }
    });
  }

  // eslint-disable-next-line no-unused-vars
  requestInput(prompt = "> ") {
    if (this.inputQueue.length > 0) {
      const input = this.inputQueue.shift();
      process.stdout.write(prompt);
      return input;
    }

    return new Promise((resolve) => {
      this.inputResolver = resolve;
      process.stdout.write(prompt);
    });
  }

  async getConfirmation(message) {
    const answer = await this.requestInput(`${message} [y/N] \u276f `);
    return answer.toLowerCase() === "y";
  }
}


export default TerminalUI;

class ToolAttemptTracker {
  constructor() {
    this.attempts = new Map();
    this.maxAttempts = 10; // Límite por defecto para evitar bucles
  }

  /**
   * Registra un intento de llamada a una herramienta
   * @param {string} name
   * @param {any} args
   * @returns {boolean} true if the attempt is allowed, false if a loop is detected
   */
  recordAttempt(name, args) {
    const argKey = JSON.stringify(args);
    const key = `${name}:${argKey}`;

    const count = (this.attempts.get(key) || 0) + 1;
    this.attempts.set(key, count);

    return count <= this.maxAttempts;
  }

  /**
   * Registra que una herramienta se ejecutó con éxito
   * @param {string} name
   */
  recordSuccess(_name) {
    // Podríamos limpiar intentos fallidos aquí si fuera necesario
  }

  /**
   * Registra que una herramienta falló
   * @param {string} _name
   */
  recordFailure(_name) {
    // Registro de fallos para análisis
  }

  reset() {
    this.attempts.clear();
  }
}


export default ToolAttemptTracker;

import logger from "./logger";
import UserInterruptException from "./exceptions";

const DESTRUCTIVE_TOOLS = [
  "removeFile",
  "writeFile",
  "replaceString",
  "executeBash",
];

class TurnProcessor {
  async #sendMessageWithRetry(message, role = "user", attempt = 1) {
    const maxRetries = 5000;
    const baseDelay = 1000;
    try {
      return await this.assistant.sendMessage(message, role);
    } catch (error) {
      if (attempt >= maxRetries) throw error;
      const isRetryable =
        !error.response ||
        [429, 500, 502, 503, 504].includes(error.response.status);
      if (!isRetryable) throw error;
      const delay = baseDelay * 2 ** (attempt - 1);
      this.ui.displayError(
        `API Error: ${error.message}. Retrying in ${delay}ms... (Attempt ${attempt}/${maxRetries})`,
      );
      await new Promise((resolve) => {
        setTimeout(resolve, delay);
      });
      return this.#sendMessageWithRetry(message, role, attempt + 1);
    }
  }

  constructor(assistant, tools, parser, engine, ui, repetitionDetector) {
    this.assistant = assistant;
    this.tools = tools;
    this.parser = parser;
    this.engine = engine;
    this.ui = ui;
    this.repetitionDetector = repetitionDetector;
  }

  async process(userInput) {
    if (!userInput) return;

    logger.info("Starting processTurn", { userInput });

    let processedInput = userInput;
    if (this.ui.renderingMode === "FOUNTAIN") {
      const nick =
        userInput.startsWith("* SCENE:") || userInput.startsWith("* ACTION:")
          ? "system"
          : this.ui.userNickname;
      processedInput = this.ui._renderFountain(nick, userInput);
    }

    let currentResponse = await this.#sendMessageWithRetry(processedInput);

    if (this.ui.renderingMode === "FOUNTAIN") {
      const formatted = this.ui._renderFountain(
        this.ui.agentNickname,
        currentResponse,
      );
      await this.assistant.popLastMessage();
      await this.assistant.injectMessage("model", formatted);
    }

    // Guard against null/filtered responses (NVIDIA/Gemini safety filters)
    const isSafetyBlock =
      currentResponse === null || currentResponse === "null";

    if (isSafetyBlock) {
      this.ui.displayError(
        "The model response was filtered by safety guards. Your last message has been removed from history to prevent blocking the conversation. Please rephrase your request.",
      );
      this.assistant.popLastMessage(); // Remove the triggering message to prevent history poisoning
      return;
    }

    let apiRecoveryAttempts = 0;
    const maxApiRecoveries = 20;

    while (
      currentResponse?.startsWith("Error:") &&
      apiRecoveryAttempts < maxApiRecoveries
    ) {
      apiRecoveryAttempts += 1;
      this.ui.displayError(
        `API Communication Error (Attempt ${apiRecoveryAttempts}/${maxApiRecoveries}): ${currentResponse}`,
      );
      // eslint-disable-next-line no-await-in-loop
      currentResponse = await this.#sendMessageWithRetry(
        `System Error: ${currentResponse}. Please attempt to recover or rephrase your last action.`,
      );
    }

    let turnComplete = false;
    let iterations = 0;
    const maxIterations = 10 ** 10;
    let consecutiveErrors = 0;

    while (!turnComplete && iterations < maxIterations) {
      iterations += 1;
      const repetitionCheck = this.repetitionDetector.addText(currentResponse);

      if (repetitionCheck !== true) {
        this.ui.displayChatMessage(
          "system",
          `-!- [RepetitionDetector] Repetition detected: ${repetitionCheck}`,
        );
        this.ui.displayError(`Repetition detected: ${repetitionCheck}`);
        currentResponse =
          "ERR: Repetition detected. Please rephrase your response.";
      }

      const toolCalls = this.parser.extractToolCalls(currentResponse);

      // UX: Separate reasoning (thought) from action
      // UX: Extract reasoning (thought) regardless of tool calls
      const thoughtMatch = currentResponse.match(
        /<thought>([\s\S]*?)<\/thought>/i,
      );
      if (thoughtMatch && thoughtMatch[1]) {
        const thought = thoughtMatch[1].trim();
        this.ui.displayThought(thought);
        logger.sessionLog(thought);
        // Remove the thought block from the response to avoid double-displaying it as text
        currentResponse = currentResponse.replace(thoughtMatch[0], "").trim();
      } else {
        // Fallback: If no explicit <thought> tags, check if there's text before the first tool call
        const firstCallIndex = currentResponse.search(
          /<(?:TOOL_CALL|tool_call)\s*>/i,
        );
        if (firstCallIndex > 0) {
          const thought = currentResponse.substring(0, firstCallIndex).trim();
          if (thought) {
            this.ui.displayThought(thought);
            logger.sessionLog(thought);
            currentResponse = currentResponse.substring(firstCallIndex).trim();
          }
        }
      }

      if (toolCalls.length === 0 || toolCalls.every((tc) => tc.error)) {
        turnComplete = true;
      } else {
        const toolResults = [];
        for (let i = 0; i < toolCalls.length; i += 1) {
          const call = toolCalls[i];
          if (call.data) {
            // Zero-Friction Intervention Check
            const isDestructive = DESTRUCTIVE_TOOLS.includes(call.data.name);
            if (this.ui.inputQueue && this.ui.inputQueue.length > 0) {
              if (isDestructive) {
                logger.info("Destructive tool interrupted by user input");
                throw new UserInterruptException();
              }
              // For non-destructive tools, we can choose to interrupt or continue.
              // To be truly responsive, we interrupt any turn if the user speaks.
              throw new UserInterruptException();
            }

            consecutiveErrors = 0;
            // eslint-disable-next-line no-await-in-loop
            const { response, result } = await this.engine.executeToolCall(
              call.data.name,
              call.data.args,
              { id: call.data.id },
            );

            if (result && result.type === "FOUNTAIN_INJECTION") {
              this.ui.displayChatMessage("system", result.content);
              this.assistant.injectMessage("user", result.content);

              const okResponse = this.parser.formatToolResponse(
                "OK",
                call.data.id,
                true,
              );
              this.assistant.injectMessage("user", okResponse);

              return;
            }

            if (
              call.data.name === "setNickname" &&
              typeof result === "string" &&
              result.startsWith("*** ")
            ) {
              const [, name] = result.match(/is now known as\s+(.+)$/);
              if (name) {
                this.ui.agentNickname = name;
              }
            }
            toolResults.push(response);
          } else if (call.error) {
            consecutiveErrors += 1;
            toolResults.push(
              `<TOOL_RESPONSE>ERR: ${call.error}</TOOL_RESPONSE>`,
            );
          }
        }

        if (consecutiveErrors >= 3) {
          turnComplete = true;
          currentResponse =
            "CRITICAL ERROR: Too many consecutive JSON validation failures. Stop using tools and explain your intent in plain text.";
          break;
        }
        // eslint-disable-next-line no-await-in-loop
        currentResponse = await this.#sendMessageWithRetry(
          this.ui.renderingMode === "FOUNTAIN"
            ? this.ui._renderFountain("system", toolResults.join("\n"))
            : toolResults.join("\n"),
          "user",
        );

        if (this.ui.renderingMode === "FOUNTAIN") {
          const formatted = this.ui._renderFountain(
            this.ui.agentNickname,
            currentResponse,
          );
          // eslint-disable-next-line no-await-in-loop
          await this.assistant.popLastMessage();
          // eslint-disable-next-line no-await-in-loop
          await this.assistant.injectMessage("model", formatted);
        }

        // Guard against null/filtered responses during tool iterations
        const isSafetyBlockTool =
          currentResponse === null || currentResponse === "null";

        if (isSafetyBlockTool) {
          this.ui.displayError(
            "The model response was filtered by safety guards during tool execution. Your last message has been removed from history. Please rephrase your request.",
          );
          this.assistant.popLastMessage(); // Remove the triggering message to prevent history poisoning
          turnComplete = true;
          break;
        }

        if (currentResponse?.startsWith("Error:")) {
          apiRecoveryAttempts += 1;
          if (apiRecoveryAttempts < maxApiRecoveries) {
            this.ui.displayError(
              `API Communication Error during tool processing (Attempt ${apiRecoveryAttempts}/${maxApiRecoveries}): ${currentResponse}`,
            );
            // eslint-disable-next-line no-await-in-loop
            // eslint-disable-next-line no-await-in-loop
            // eslint-disable-next-line no-await-in-loop
            currentResponse = await this.#sendMessageWithRetry(
              `System Error: ${currentResponse}. Please attempt to recover or rephrase your last action.`,
            );
          } else {
            this.ui.displayError(
              "Critical API failure during tool processing. Halting.",
            );
            return;
          }
        }
      }
    }

    if (iterations >= maxIterations)
      this.ui.displayError("Maximum tool iterations reached.");

    const cleanedResponse = this.parser.cleanResponse(currentResponse);
    const finalResponse = cleanedResponse;
    if (finalResponse.trim()) {
      this.ui.displayChatMessage(this.ui.agentNickname, finalResponse);
    }
  }
}


export default TurnProcessor;

class ConversationState {
  constructor(userNickname = "user", agentNickname = "assistant") {
    this.userNickname = userNickname;
    this.agentNickname = agentNickname;
    this.history = [];
    this.renderingMode = "IRC";
  }

  setRenderingMode(mode) {
    this.renderingMode = mode;
  }

  getTimestamp() {
    return new Date().toLocaleTimeString("en-GB", {
      hour: "2-digit",
      minute: "2-digit",
    });
  }

  _formatMessage(role, text, timestamp = this.getTimestamp()) {
    if (this.renderingMode === "FOUNTAIN") return text;

    if (
      text.startsWith("---") ||
      text.startsWith("***") ||
      text.startsWith("<TOOL_RESPONSE>")
    ) {
      return `[${timestamp}] ${text}`;
    }
    const nickname = role === "user" ? this.userNickname : this.agentNickname;
    return `[${timestamp}] <${nickname}> ${text}`;
  }

  addMessage(role, text, timestamp = null) {
    const normalizedRole =
      role === "model" || role === "assistant" ? "model" : "user";

    const ts = timestamp || this.getTimestamp();
    const formattedText = this._formatMessage(normalizedRole, text, ts);
    this.history.push({
      role: normalizedRole,
      text: formattedText,
      timestamp: ts,
    });
    return formattedText;
  }

  hardReset(historyOverride = null) {
    this.history = historyOverride || [];
  }

  popLastMessage() {
    if (this.history.length > 0) this.history.pop();
  }

  getRawHistory() {
    return this.history;
  }
}


export default ConversationState;

import axios from "axios";
import axiosRetry from "axios-retry";
import logger from "./logger";

class GeminiAdapter {
  constructor(ui, userNickname = "user", agentNickname = "assistant") {
    this.ui = ui;
    this.apiKey = process.env.GEMINI_API_KEY || process.env.GOOGLE_API_KEY;
    this.history = [];
    this.currentModel = "gemini-2.0-flash";
    this.systemInstruction = null;
    this.temperature = 0.7;
    this.lastPayload = null;
    this.userNickname = userNickname;
    this.agentNickname = agentNickname;
    this.renderingMode = "IRC";
    this.lastRequestTime = 0;
    this.rpmLimit = 15;

    this.client = axios.create({
      timeout: 600000,
    });

    axiosRetry(this.client, {
      retries: 5,
      retryDelay: axiosRetry.exponentialDelay,
      retryCondition: (error) => {
        const status = error.response?.status;
        const recoverableStatuses = [429, 500, 502, 503, 504];
        return (
          axiosRetry.isNetworkOrIdempotentRequestError(error) ||
          recoverableStatuses.includes(status)
        );
      },
      onRetry: (retryCount, error) => {
        const time = new Date().toLocaleTimeString("en-GB", {
          hour: "2-digit",
          minute: "2-digit",
          second: "2-digit",
          hour12: false,
        });
        const msg = `[${time}] -!- [GeminiAdapter] API Retry ${retryCount}/5 due to: ${error.response?.status || error.message}`;
        logger.warn(msg);
        if (this.ui && this.ui.displayInfo) {
          this.ui.displayInfo(`Reintentando conexión... (${retryCount}/5)`);
        }
      },
    });
  }

  async _applyRateLimit() {
    const minInterval = 60000 / this.rpmLimit;
    const now = Date.now();
    const elapsed = now - this.lastRequestTime;

    if (elapsed < minInterval) {
      const waitTime = minInterval - elapsed;
      logger.debug(
        `[GeminiAdapter] Rate Limit: Waiting ${waitTime / 1000}s to maintain ${this.rpmLimit} RPM`,
      );
      await new Promise((resolve) => {
        setTimeout(resolve, waitTime);
      });
    }
    this.lastRequestTime = Date.now();
  }

  setRenderingMode(mode) {
    this.renderingMode = mode;
  }

  startChat(modelName, systemInstruction, temperature = 0.7) {
    this.currentModel = modelName || this.currentModel;
    this.systemInstruction = systemInstruction;
    this.temperature = temperature;
    this.history = [];
  }

  _buildPayload() {
    const contents = JSON.parse(JSON.stringify(this.history)).map((c) => {
      // eslint-disable-next-line no-unused-vars
      const { timestamp, ...rest } = c;
      if (rest.role === "server") {
        rest.role = "user";
      }
      return rest;
    });
    const payload = {
      contents,
      generationConfig: {
        temperature: this.temperature,
      },
    };

    if (this.systemInstruction) {
      payload.systemInstruction = {
        parts: [{ text: this.systemInstruction }],
      };
    }

    return payload;
  }

  _filterThoughts(text) {
    if (!text) return "";
    let cleaned = text.replace(/<(thought|reasoning)>[\s\S]*?<\/\1>/gi, "");
    cleaned = cleaned.replace(/^(\[\d{2}:\d{2}:\d{2}\]\s*<[^>]+>\s*)+/g, "");
    return cleaned.trim();
  }

  _formatMessage(role, text, timestamp) {
    if (this.renderingMode === "FOUNTAIN") return text;

    if (
      role === "server" ||
      text.startsWith("---") ||
      text.startsWith("***") ||
      text.startsWith("<TOOL_RESPONSE>")
    ) {
      return `[${timestamp}] ${text}`;
    }
    const nickname = role === "user" ? this.userNickname : this.agentNickname;
    return `[${timestamp}] <${nickname}> ${text}`;
  }

  async sendMessage(message, role = "user") {
    await this._applyRateLimit();
    const timestamp = new Date().toLocaleTimeString("en-GB", {
      hour: "2-digit",
      minute: "2-digit",
      second: "2-digit",
      hour12: false,
    });
    const formattedMessage = this._formatMessage(role, message, timestamp);
    const parts = [{ text: formattedMessage }];
    this.history.push({
      role,
      parts,
      timestamp,
    });

    const payload = this._buildPayload();
    this.lastPayload = JSON.parse(JSON.stringify(payload));
    const modelName = this.currentModel.replace(/^models\//, "");
    const url = `https://generativelanguage.googleapis.com/v1beta/models/${modelName}:generateContent?key=${this.apiKey}`;

    try {
      const response = await this.client.post(url, payload);
      const { data } = response;

      const { candidates } = data;
      if (!candidates || candidates.length === 0) {
        return "Error: No response candidates returned (possible safety block).";
      }

      const candidate = candidates[0];
      if (candidate.finishReason === "SAFETY") {
        return "Error: Response blocked by safety filters.";
      }

      const { content } = candidate;
      if (!content || !content.parts || content.parts.length === 0) {
        return "Error: No content parts returned.";
      }

      let textContent = content.parts.map((p) => p.text).join("");
      textContent = this._filterThoughts(textContent);

      if (textContent) {
        const msgTimestamp = new Date().toLocaleTimeString("en-GB", {
          hour: "2-digit",
          minute: "2-digit",
          second: "2-digit",
          hour12: false,
        });
        const msgFormatted = this._formatMessage(
          "model",
          textContent,
          msgTimestamp,
        );
        this.history.push({
          role: "model",
          parts: [{ text: msgFormatted }],
          timestamp: msgTimestamp,
        });
        return textContent;
      }

      return "Error: Empty response";
    } catch (e) {
      const errorMsg = e.response?.data?.error?.message || e.message;
      const error = new Error(errorMsg);
      error.name = "APIError";
      throw error;
    }
  }

  injectMessage(role, content, timestamp = null) {
    const ts =
      timestamp ||
      new Date().toLocaleTimeString("en-GB", {
        hour: "2-digit",
        minute: "2-digit",
        second: "2-digit",
        hour12: false,
      });
    const formattedMessage = this._formatMessage(role, content, ts);
    this.history.push({
      role,
      parts: [{ text: formattedMessage }],
      timestamp: ts,
    });
  }

  hardReset(historyOverride = null) {
    this.history = historyOverride || [];
  }

  getHistory() {
    return this.history;
  }

  popLastMessage() {
    if (this.history.length > 0) {
      this.history.pop();
    }
  }

  updateNicknames(userNickname, agentNickname) {
    this.userNickname = userNickname;
    this.agentNickname = agentNickname;
  }

  async getAvailableModels() {
    try {
      const url = `https://generativelanguage.googleapis.com/v1beta/models?key=${this.apiKey}`;
      const response = await this.client.get(url);
      const models = response.data.models || [];
      return models
        .filter((m) => m.name.includes("gemini") || m.name.includes("gemma"))
        .map((m) => m.name);
    } catch (e) {
      console.error(`Error fetching models: ${e.message}`);
      return ["models/gemini-2.0-flash", "models/gemini-1.5-flash"];
    }
  }
}


export default GeminiAdapter;

import fs from "fs";
import path from "path";

const LOG_FILE = path.join(process.cwd(), "log", "memento.log");

class MementoManager {
  async pushMemory(role, scope, value, key = null) {
    // 1. Handle Rank Increments for references
    this._incrementReferencedRanks(value);

    // 2. Prepare new entry
    const entries = this._readAll();
    const nextId = entries.length + 1;
    const timestamp = new Date()
      .toISOString()
      .replace("T", " ")
      .substring(0, 19);
    const category = scope || "general";
    const keyTag = key ? ` [Key: ${key}]` : "";

    const entry = `[ID: ${nextId}] [${timestamp}] [Rank: 0] <${category}>${keyTag} ${value}\n`;

    fs.appendFileSync(LOG_FILE, entry, "utf8");
    return `Memory stored in memento.log as entry #${nextId}. Referenced ranks updated.`;
  }

  async pullMemory(scope, key, direction = "next") {
    if (!fs.existsSync(LOG_FILE)) return "ERR: Memory log not found.";

    const content = fs.readFileSync(LOG_FILE, "utf8");
    const lines = content.split("\n").filter(Boolean);

    // Filter by scope and key
    const matches = lines.filter((line) => {
      const scopeMatch = scope ? line.includes(`<${scope}>`) : true;
      const keyMatch = key ? line.includes(`[Key: ${key}]`) : true;
      return scopeMatch && keyMatch;
    });

    if (matches.length === 0) return "No matching memories found.";

    // Simple direction logic: return the last match for 'next' (most recent)
    return direction === "next" ? matches[matches.length - 1] : matches[0];
  }

  _incrementReferencedRanks(text) {
    if (!fs.existsSync(LOG_FILE)) return;

    const refPattern = /#(\d+)/g;
    const matches = [...text.matchAll(refPattern)];
    if (matches.length === 0) return;

    const referencedIds = matches.map((m) => m[1]);
    const content = fs.readFileSync(LOG_FILE, "utf8");
    let modified = false;

    const lines = content.split("\n");
    const updatedLines = lines.map((line) => {
      if (!line) return line;

      const idMatch = line.match(/^\[ID: (\d+)\]/);
      if (idMatch && referencedIds.includes(idMatch[1])) {
        modified = true;
        return line.replace(/(\[Rank: )(\d+)(\])/, (match, p1, p2, p3) => {
          const newRank = parseInt(p2, 10) + 1;
          return `${p1}${newRank}${p3}`;
        });
      }
      return line;
    });

    if (modified) {
      fs.writeFileSync(LOG_FILE, updatedLines.join("\n"), "utf8");
    }
  }

  _readAll() {
    if (!fs.existsSync(LOG_FILE)) return [];
    return fs.readFileSync(LOG_FILE, "utf8").trim().split("\n").filter(Boolean);
  }
}


export default MementoManager;

