  startChat(modelName, systemInstruction, temperature = 0.7) {
    this.currentModel = modelName || this.currentModel;
    this.systemInstruction = systemInstruction;
    this.temperature = temperature;
    this.state.hardReset();
    logger.info("NvidiaAdapter: Chat started", {
      model: this.currentModel,
      temperature,
    });
  }

  _filterThoughts(text) {
    if (!text) return "";
    let cleaned = text.replace(/<(thought|reasoning)>[\s\S]*?<\/\1>/gi, "");
    cleaned = cleaned.replace(/^(\[\d{2}:\d{2}:\d{2}\]\s*<[^>]+>\s*)+/g, "");
    return cleaned.trim();
  }

  async sendMessage(message, role = "user", maxTokens = 512) {
    this.state.addMessage(role, message);

    const history = this.state.getRawHistory();
    const processedHistory =
      this.state.renderingMode === "CLEAN"
        ? history.map((m) => ({
            ...m,
            text: m.text
              .replace(/^(\[\d{2}:\d{2}:\d{2}\]\s*<[^>]+>\s*)+/g, "")
              .trim(),
          }))
        : history;

    const payload = PayloadMapper.toNvidia(
      processedHistory,
      this.systemInstruction,
      this.temperature,
    );
    payload.model = this.currentModel;
    payload.max_tokens = maxTokens;
    this.lastPayload = payload;

    try {
      logger.debug("NvidiaAdapter: Sending request", {
        model: this.currentModel,
        payload,
      });
      const data = await this.restClient.chatCompletions(payload);
      const rawContent = data.choices?.[0]?.message?.content || "";
      const content = this._filterThoughts(rawContent);

      if (content) {
        logger.info("NvidiaAdapter: Response received", {
          length: content.length,
        });
        this.state.addMessage("model", content);
        return content;
      }
      logger.warn("NvidiaAdapter: Empty response received");
      return "Error: Empty response from NVIDIA";
    } catch (e) {
      const errorMsg = e.response?.data?.error?.message || e.message;
      logger.error("NvidiaAdapter: Request failed", { error: errorMsg });
      return `Error: ${errorMsg}`;
    }
  }

  injectMessage(role, content, timestamp = null) {
    this.state.addMessage(role, content, timestamp);
  }

  setRenderingMode(mode) {
    this.state.setRenderingMode(mode);
  }

  hardReset(historyOverride = null) {
    this.state.hardReset(historyOverride);
    logger.info("NvidiaAdapter: State hard reset");
  }

  getHistory() {
    return this.state.getRawHistory();
  }

  popLastMessage() {
    this.state.popLastMessage();
  }

  updateNicknames(userNickname, agentNickname) {
    this.state.userNickname = userNickname;
    this.state.agentNickname = agentNickname;
  }

  async getAvailableModels() {
    try {
      const data = await this.restClient.get("models");
      const models = data.data?.map((m) => m.id) || [];
      logger.info("NvidiaAdapter: Models fetched", { count: models.length });
      return models;
    } catch (e) {
      logger.error("NvidiaAdapter: Error fetching models", {
        error: e.message,
      });
      return ["models/gemini-2.0-flash", "models/gemini-1.5-flash"];
    }
  }

  async checkAvailability(modelName) {
    try {
      const payload = {
        model: modelName,
        messages: [{ role: "user", content: "hi" }],
        max_tokens: 1,
      };

      await this.restClient.chatCompletions(payload);
      return true;
    } catch (e) {
      if (e.response && e.response.status === 404) {
        return false;
      }
      return true;
    }
  }

  countTokens(contents) {
    const totalChars = contents.reduce(
      (acc, msg) => acc + (msg.text?.length || 0),
      0,
    );
    return Math.floor(totalChars / 4);
  }

  async close() {
    // No resources to clean up for NvidiaAdapter
  }
}


export default NvidiaAdapter;

import axios from "axios";
import logger from "./logger";
import NvidiaRetryHandler from "./retryHandler";

class NvidiaRestClient {
  constructor(configManager) {
    this.apiKey = process.env.NVIDIA_API_KEY;
    this.baseUrl = "https://integrate.api.nvidia.com/v1";
    this.configManager = configManager;
    this.lastRequestTime = 0;
    this.retryHandler = new NvidiaRetryHandler();
    this.client = axios.create({
      baseURL: this.baseUrl,
      headers: {
        Authorization: `Bearer ${this.apiKey}`,
        "Content-Type": "application/json",
        Accept: "application/json",
      },
      timeout: 60000,
    });
  }

  async _applyRateLimit(currentTokens = 1000) {
    let rpmLimit = parseInt(this.configManager.get("rpm_limit", 15), 10);
    const tpmLimit = parseInt(this.configManager.get("tpm_limit", 15000), 10);
    const autoRpmEnabled = this.configManager.get("auto_rpm_enabled", false);

    if (autoRpmEnabled) {
      rpmLimit = Math.max(
        1,
        Math.floor(tpmLimit / Math.max(currentTokens, 1000)),
      );
      logger.debug(
        `Nvidia Auto-RPM: Adjusted limit to ${rpmLimit} based on tokens`,
      );
    }

    const minInterval = 60000 / rpmLimit;
    const now = Date.now();
    const elapsed = now - this.lastRequestTime;

    if (elapsed < minInterval) {
      const waitTime = minInterval - elapsed;
      logger.debug(
        `Nvidia Rate Limit: Waiting ${waitTime / 1000}s to maintain ${rpmLimit} RPM`,
      );
      await new Promise((resolve) => {
        setTimeout(resolve, waitTime);
      });
    }
    this.lastRequestTime = Date.now();
  }

  async chatCompletions(payload, stream = false) {
    const url = "/chat/completions";
    const requestPayload = { ...payload, stream };

    const tokenEstimate =
      requestPayload.messages?.reduce(
        (acc, msg) => acc + Math.floor((msg.content?.length || 0) / 4),
        0,
      ) || 1000;

    await this._applyRateLimit(tokenEstimate);

    if (stream) {
      throw new Error("Streaming not yet implemented in JS RestClient");
    }

    const request = () => this.client.post(url, requestPayload);
    const response = await this.retryHandler.execute(request);
    return response.data;
  }

  async get(endpoint) {
    await this._applyRateLimit();
    const request = () => this.client.get(`/${endpoint}`);
    const response = await this.retryHandler.execute(request);
    return response.data;
  }

  // eslint-disable-next-line no-empty-function
  async close() {}
}


export default NvidiaRestClient;

import logger from "./logger";

class NvidiaRetryHandler {
  constructor(maxRetries = 5000, callback = null) {
    this.maxRetries = maxRetries;
    this.callback = callback;
  }

  setCallback(callback) {
    this.callback = callback;
  }

  async execute(func, ...args) {
    const run = async (retries) => {
      try {
        return await func(...args);
      } catch (e) {
        const status = e.response?.status;
        if (retries >= this.maxRetries) throw e;

        let delay = 2 ** retries * 1000;
        let msg = "";

        if (status === 429) {
          const retryAfter = e.response.headers["retry-after"];
          if (retryAfter && !Number.isNaN(Number(retryAfter))) {
            delay = parseInt(retryAfter, 10) * 1000;
          }
          msg = `Rate limited (429). Retrying in ${delay / 1000}s...`;
        } else if ([500, 502, 503, 504].includes(status)) {
          msg = `Server error (${status}). Retrying in ${delay / 1000}s...`;
        } else if (status === 404) {
          logger.error("Model not found (404). Stopping execution.");
          throw e;
        } else {
          msg = `Unexpected error ${e.message}. Retrying in ${delay / 1000}s...`;
        }

        logger.warn(msg);
        if (this.callback) this.callback(msg);

        await new Promise((resolve) => {
          setTimeout(resolve, delay);
        });
        return run(retries + 1);
      }
    };
    return run(0);
  }
}


export default NvidiaRetryHandler;

import axios from "axios";

class TransportLayer {
  /**
   * Generic HTTP GET request
   */
  async get(url, params = {}, headers = {}) {
    const response = await axios.get(url, { params, headers, timeout: 60000 });
    return response.data;
  }

  /**
   * Generic HTTP POST request with basic retry logic
   */
  async post(url, payload, headers = {}, retries = 3) {
    const run = async (attempt) => {
      try {
        const response = await axios.post(url, payload, {
          headers,
          timeout: 60000,
        });
        return response.data;
      } catch (e) {
        const status = e.response?.status;
        const isTimeout = e.code === "ECONNABORTED";
        const isRetryable =
          !isTimeout && (status === 429 || (status >= 500 && status <= 599));

        if (attempt >= retries - 1 || !isRetryable) {
          throw e;
        }

        // Exponential backoff
        await new Promise((resolve) => {
          setTimeout(resolve, 2 ** attempt * 1000);
        });
        return run(attempt + 1);
      }
    };
    return run(0);
  }
}


export default TransportLayer;

import "dotenv/config";
import fs from "fs";
import { Command } from "commander";
import { GeminiAdapter } from "./infrastructure/gemini/adapter";
import NvidiaAdapter from "./adapter";
import TerminalUI from "./terminalUI";
import ChatManager from "./chatManager";
import ConfigManager from "./configManager";
import { SYSTEM_INSTRUCTION, AVAILABLE_TOOLS } from "./tools/registry";
import * as memoryTools from "./tools/memoryTools";

async function main() {
  const program = new Command();

  program
    .name("paser-mini")
    .description("Minimalist Autonomous Agent (JS Port)")
    .option("-m, --message <message>", "Initial message to send")
    .option(
      "-si, --system-instruction <instruction>",
      "Custom system instructions",
    )
    .option(
      "-isi, --inject-system-instruction <instruction>",
      "Inject instruction at the start of system prompt",
    )
    .option(
      "-fsi, --file-system-instruction <path>",
      "Path to file for system instruction injection",
    )
    .option("-nsi, --no-system-instruction", "Run without system instructions")
    .option(
      "--github-mode",
      "Run in GitHub mode: process issues with #ai-assistance",
    )
    .parse(process.argv);

  const options = program.opts();
  const configManager = new ConfigManager();

  if (options.githubMode) {
    const { GitHubModeOrchestrator } =
      await import("./core/githubModeOrchestrator");
    const tools = options.noSystemInstruction ? {} : AVAILABLE_TOOLS;
    const orchestrator = new GitHubModeOrchestrator(
      options.noSystemInstruction
        ? ""
        : options.systemInstruction || SYSTEM_INSTRUCTION,
      tools,
    );
    await orchestrator.runForever();
    return;
  }

  const ui = new TerminalUI();

  const provider = configManager.get("provider", "Gemini");
  const userNick = configManager.get("user_nickname", "user");
  const agentNick = configManager.get("agent_nickname", "assistant");
  const assistant =
    provider === "NVIDIA"
      ? new NvidiaAdapter(configManager, userNick, agentNick)
      : new GeminiAdapter(ui, userNick, agentNick);

  let sysInstr = "";
  if (!options.noSystemInstruction) {
    const baseInstr = options.systemInstruction || SYSTEM_INSTRUCTION;
    let injection = "";

    if (options.injectSystemInstruction) {
      injection = options.injectSystemInstruction;
    } else if (options.fileSystemInstruction) {
      try {
        injection = fs.readFileSync(options.fileSystemInstruction, "utf8");
      } catch (e) {
        console.error(`Error reading instruction file: ${e.message}`);
        process.exit(1);
      }
    }

    sysInstr = injection
      ? `IDENTITY AND PERSONA:\n${injection}\n\nCORE OPERATIONAL PROTOCOLS:\n${baseInstr}`
      : baseInstr;
  }

  const chatManager = new ChatManager(
    assistant,
    options.noSystemInstruction ? {} : AVAILABLE_TOOLS,
    sysInstr,
    ui,
  );

  chatManager.configManager = configManager;

  memoryTools.setMemoryContext(assistant, chatManager);
  await chatManager.run(options.message);
}

process.on("unhandledRejection", (reason, promise) => {
  console.error("Unhandled Rejection at:", promise, "reason:", reason);
});

process.on("uncaughtException", (err) => {
  console.error("Uncaught Exception thrown:", err);
});

main().catch((err) => {
  console.error("Critical Error:", err);
  process.exit(1);
});

import { exec } from "child_process";
import { promisify } from "util";
import ConfigManager from "./configManager";

const execPromise = promisify(exec);
const config = new ConfigManager();

const newAgent = async ({ message = null, args = [] }) => {
  try {
    const timeout = config.get("instance_timeout", 300);
    let cmd = "node src_js/main.js --instance-mode";

    if (message) cmd += ` -m "${message}"`;
    if (args.length > 0) cmd += ` ${args.join(" ")}`;

    const { stdout, stderr } = await execPromise(cmd, {
      timeout: timeout * 1000,
    });
    return `Nueva instancia finalizada.\nSTDOUT:\n${stdout}\nSTDERR:\n${stderr}`;
  } catch (e) {
    return `ERR: Error al lanzar la nueva instancia: ${e.message}`;
  }
};


export default newAgent;

import MementoManager from "./manager";

const memento = new MementoManager();

let currentAssistant = null;
let currentChatManager = null;

export const setMemoryContext = (assistant, chatManager) => {
  currentAssistant = assistant;
  currentChatManager = chatManager;
};

export const pushMemory = async (value) => {
  try {
    if (!value) {
      return "ERR: No value provided for memory.";
    }

    return await memento.pushMemory("agent", "general", String(value), null);
  } catch (e) {
    return `ERR: ${e.message}`;
  }
};

export const pullMemory = async ({ scope, key, direction }) => {
  try {
    return await memento.pullMemory(scope, key, direction);
  } catch (e) {
    return `ERR: ${e.message}`;
  }
};

export const getTokenCount = async () => {
  try {
    if (!currentAssistant || !currentChatManager) {
      return "ERR: Memory context not initialized.";
    }

    // Local fast estimation: character count / 4 (matches RPD-saving strategy)
    const systemInstruction = currentChatManager.systemInstruction || "";
    const historyData =
      typeof currentAssistant.history === "string"
        ? currentAssistant.history
        : JSON.stringify(currentAssistant.history || []);

    const totalLength = systemInstruction.length + historyData.length;
    const count = Math.ceil(totalLength / 4);
    const limit = currentChatManager.contextWindowLimit || 250000;

    const percentage = (count / limit) * 100;
    return `Current tokens (est.): ${count} / ${limit} (${percentage.toFixed(2)}%)`;
  } catch (e) {
    return `ERR: ${e.message}`;
  }
};

